mapper.select:
SELECT COUNT(1) > 0
FROM reservations
WHERE resource_id = #{resourceId}
  AND start_at < #{endAt}
  AND end_at > #{startAt}
  AND deleted = FALSE
  AND status NOT IN ('CANCELLED', 'REJECTED')

mapper.insert:
INSERT INTO reservation_occupied_slots (resource_id, slot_start_at, reservation_id)
SELECT #{resourceId}, slot_start_at, #{reservationId}
FROM (
    SELECT FROM_UNIXTIME((FLOOR(UNIX_TIMESTAMP(#{startAt}) / (#{slotMinutes} * 60)) + sequence_number) * #{slotMinutes} * 60) AS slot_start_at
    FROM (
        SELECT ones.n + tens.n * 10 + hundreds.n * 100 AS sequence_number
        FROM (SELECT 0 n UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4 UNION ALL SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8 UNION ALL SELECT 9) ones
        CROSS JOIN (SELECT 0 n UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4 UNION ALL SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8 UNION ALL SELECT 9) tens
        CROSS JOIN (SELECT 0 n UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4 UNION ALL SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8 UNION ALL SELECT 9) hundreds
    ) numbers
) slots
WHERE slot_start_at < #{endAt}

mapper.select:
SELECT id, user_id AS userId, resource_id AS resourceId, resource_name AS resourceName,
       resource_type AS resourceType, start_at AS startAt, end_at AS endAt,
       status, approval_level AS approvalLevel, created_at AS createdAt, updated_at AS updatedAt
FROM reservations
WHERE deleted = FALSE
AND user_id = #{userId}
AND status = #{status}
AND resource_name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}
